import numpy as np
from scipy.special import wright_bessel
from scipy.integrate import quad


class Solver:
    def solve(self, problem, **kwargs):
        """Solve integration problem with scipy.integrate.quad."""
        a = np.array(problem["a"])
        b = np.array(problem["b"])
        lower = np.array(problem["lower"])
        upper = np.array(problem["upper"])

        # Define the function to integrate
        def integrand(x, a, b):
            return wright_bessel(a, b, x)

        # Perform the numerical integration
        results = []
        for ai, bi, li, ui in zip(a, b, lower, upper):
            result, _ = quad(integrand, li, ui, args=(ai, bi))
            results.append(result)

        return {"result": results}
